import Link from './Link'

const Simulations = () => (
    <div>
        <h2>Simulations</h2>
        <ol>
           {simulations.map(({ link, title })=><Link link={link} title={title}/>)}
        </ol>
    </div>
)

const simulations = [
    {
        title: "Dynamic learning",
        link: "https://www.dynamiclearning.io/"
    }
]

export default Simulations
